#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Carp qw(croak);

# SECURITY NOTE: Never hardcode credentials in source code.
# The following pattern is INSECURE and must NOT be used:
#
#   my $dbh = DBI->connect("DBI:mysql:database=legacy_db;host=localhost", "dbuser", "DbPass123")
#
# Instead, load all connection parameters from environment variables
# or a secrets manager as shown below.

sub get_db_connection {
    # Load connection parameters from environment variables
    my $db_name = $ENV{'LEGACY_DB_NAME'}
        // croak("Environment variable LEGACY_DB_NAME is not set");
    my $db_host = $ENV{'LEGACY_DB_HOST'}
        // croak("Environment variable LEGACY_DB_HOST is not set");
    my $db_port = $ENV{'LEGACY_DB_PORT'} // '3306';
    my $db_user = $ENV{'LEGACY_DB_USER'}
        // croak("Environment variable LEGACY_DB_USER is not set");
    my $db_pass = $ENV{'LEGACY_DB_PASS'}
        // croak("Environment variable LEGACY_DB_PASS is not set");

    # Optional: load from a secrets manager file (e.g., HashiCorp Vault agent,
    # AWS Secrets Manager sidecar, or a mounted secrets volume)
    # If a secrets file path is provided, prefer it over env vars for the password.
    if (my $secret_file = $ENV{'LEGACY_DB_PASS_FILE'}) {
        if (-f $secret_file && -r $secret_file) {
            open my $fh, '<', $secret_file
                or croak("Cannot read secret file '$secret_file': $!");
            $db_pass = do { local $/; <$fh> };
            close $fh;
            # Remove any trailing newline from secret file
            chomp $db_pass;
        } else {
            croak("Secret file '$secret_file' does not exist or is not readable");
        }
    }

    my $dsn = "DBI:mysql:database=${db_name};host=${db_host};port=${db_port}";

    my $dbh = DBI->connect(
        $dsn,
        $db_user,
        $db_pass,
        {
            RaiseError           => 1,
            AutoCommit           => 1,
            PrintError           => 0,
            mysql_enable_utf8mb4 => 1,
            mysql_auto_reconnect => 1,
            mysql_connect_timeout => 10,
        }
    ) or croak("Failed to connect to database: " . DBI->errstr);

    # Clear the password from memory as soon as possible
    $db_pass = "\0" x length($db_pass);
    undef $db_pass;

    return $dbh;
}

sub verify_connection {
    my ($dbh) = @_;

    eval {
        my $sth = $dbh->prepare("SELECT 1");
        $sth->execute();
        my ($result) = $sth->fetchrow_array();
        $sth->finish();

        if ($result == 1) {
            print "Database connection verified successfully.\n";
        } else {
            croak("Connection verification returned unexpected result");
        }
    };
    if ($@) {
        croak("Database connection verification failed: $@");
    }

    return 1;
}

# Main execution
